// 주간 집계 통계 계산 및 LLM 프롬프트 생성
const items = $input.all();

if (!items.length) {
  return [{ json: { skip: true } }];
}

const weekStart = new Date();
// 지난 주 월요일
const day = weekStart.getDay();
const diff = weekStart.getDate() - day + (day === 0 ? -6 : 1) - 7;
weekStart.setDate(diff);
weekStart.setHours(0, 0, 0, 0);
const weekStartISO = weekStart.toISOString();

// 시스템별 요약 집계
const systemSummary = {};
items.forEach(item => {
  const d = item.json;
  if (!systemSummary[d.system_name]) {
    systemSummary[d.system_name] = {
      system_id: d.system_id,
      display_name: d.display_name,
      total_anomaly_hours: 0,
      worst_severity: 'normal',
      metrics: []
    };
  }
  const s = systemSummary[d.system_name];
  s.total_anomaly_hours += parseFloat(d.total_anomaly_hours) || 0;
  if (d.worst_severity === 'critical' || (d.worst_severity === 'warning' && s.worst_severity !== 'critical')) {
    s.worst_severity = d.worst_severity;
  }
  s.metrics.push(`${d.collector_type}/${d.metric_group}: ${d.trend_summary || '정상'}`);
});

const systemLines = Object.values(systemSummary)
  .sort((a, b) => b.total_anomaly_hours - a.total_anomaly_hours)
  .slice(0, 10)
  .map(s => `- ${s.display_name}: 이상 ${Math.round(s.total_anomaly_hours)}시간, 최고 심각도: ${s.worst_severity}`);

const llmPrompt = `다음은 지난 7일간 시스템 모니터링 집계 데이터입니다.

[시스템별 주간 현황 (이상 시간 순)]
${systemLines.join('\n')}

총 ${Object.keys(systemSummary).length}개 시스템 모니터링. 한국어로 2-3 문장의 핵심 요약을 작성해 주세요. 가장 주의가 필요한 시스템과 전체적인 추세를 포함해 주세요.`;

const weeklyMetricsJson = JSON.stringify({
  system_count: Object.keys(systemSummary).length,
  total_anomaly_hours: Object.values(systemSummary).reduce((a, s) => a + s.total_anomaly_hours, 0),
  critical_systems: Object.values(systemSummary).filter(s => s.worst_severity === 'critical').length
});

return [{
  json: {
    week_start_iso: weekStartISO,
    llm_prompt: llmPrompt,
    system_summary: systemSummary,
    weekly_metrics_json: weeklyMetricsJson,
    item_count: items.length,
    skip: false
  }
}];

// LLM 응답 파싱 및 Teams 카드 생성
const llmResp = $input.first().json;
const prevData = $('주간 집계 계산 및 LLM 프롬프트 생성').first().json;

const llmSummary = llmResp?.choices?.[0]?.message?.content 
  || llmResp?.response 
  || llmResp?.content 
  || '주간 요약 생성 실패';

const weekStart = new Date(prevData.week_start_iso);
const weekEnd = new Date(weekStart);
weekEnd.setDate(weekEnd.getDate() + 6);
const dateRange = `${weekStart.toLocaleDateString('ko-KR')} ~ ${weekEnd.toLocaleDateString('ko-KR')}`;

const metricsObj = JSON.parse(prevData.weekly_metrics_json || '{}');

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        { type: 'TextBlock', text: `📊 주간 모니터링 리포트: ${dateRange}`, weight: 'Bolder', size: 'Medium' },
        { type: 'TextBlock', text: llmSummary, wrap: true },
        {
          type: 'FactSet',
          facts: [
            { title: '모니터링 시스템', value: `${metricsObj.system_count || 0}개` },
            { title: '총 이상 발생',    value: `${Math.round(metricsObj.total_anomaly_hours || 0)}시간` },
            { title: 'Critical 시스템', value: `${metricsObj.critical_systems || 0}개` }
          ]
        }
      ]
    }
  }]
};

return [{
  json: {
    ...prevData,
    llm_summary: llmSummary,
    teams_card: JSON.stringify(card)
  }
}];
